dashboard.definition:
{
  "title": "Source - ServiceBus",
  "description": "Azure Service Bus messaging — queue health, dead letters, and message flow monitoring",
  "dataSources": {
    "ds_total_messages": {
      "type": "ds.search",
      "name": "Total Messages Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" by _time span=1h"
      }
    },
    "ds_dead_letters": {
      "type": "ds.search",
      "name": "Dead Letter Messages",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" status=\"DeadLettered\" | stats count"
      }
    },
    "ds_price_updates": {
      "type": "ds.search",
      "name": "Price Update Messages",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" label=\"PriceUpdate\" OR eventType=\"PriceUpdate\" | stats count"
      }
    },
    "ds_message_rate": {
      "type": "ds.search",
      "name": "Avg Message Rate per Hour",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" | timechart span=1h count | stats avg(count) as count | eval count=round(count,0)"
      }
    },
    "ds_message_flow": {
      "type": "ds.search",
      "name": "Message Flow Over Time",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" | timechart span=1h count"
      }
    },
    "ds_message_type_dist": {
      "type": "ds.search",
      "name": "Message Type Distribution",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" | eval msg_type=case(status=\"DeadLettered\",\"Dead Letter\",label=\"PriceUpdate\" OR eventType=\"PriceUpdate\",\"Price Update\",1=1,\"Order Message\") | stats count by msg_type | sort -count"
      }
    },
    "ds_top_queues": {
      "type": "ds.search",
      "name": "Top Message Queues",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" queueName=* | stats count by queueName | sort -count | head 15 | rename queueName as \"Queue\""
      }
    },
    "ds_recent_dead_letters": {
      "type": "ds.search",
      "name": "Recent Dead Letter Events",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:azure:servicebus\" status=\"DeadLettered\" | table _time host queueName label messageId status | sort -_time | head 30 | rename queueName as \"Queue\" label as \"Message Type\" messageId as \"Message ID\" status as \"Status\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — ServiceBus\n\n**Sourcetype:** `FAKE:azure:servicebus` | **Coverage:** Azure Service Bus (order processing queues) | **Format:** JSON\n\n**Why monitor?** Prevent data loss — monitor message queue health, detect dead letters before they cause pricing errors.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_messages": {
      "type": "splunk.singlevalue",
      "title": "Total Messages",
      "dataSources": { "primary": "ds_total_messages" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_dead_letters": {
      "type": "splunk.singlevalue",
      "title": "Dead Letters",
      "dataSources": { "primary": "ds_dead_letters" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_price_updates": {
      "type": "splunk.singlevalue",
      "title": "Price Updates",
      "dataSources": { "primary": "ds_price_updates" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_message_rate": {
      "type": "splunk.singlevalue",
      "title": "Avg Messages / Hour",
      "dataSources": { "primary": "ds_message_rate" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_message_flow": {
      "type": "splunk.area",
      "title": "Message Flow Over Time",
      "dataSources": { "primary": "ds_message_flow" },
      "options": {
        "legendDisplay": "off",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Messages / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColors": ["#00D2FF"]
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_message_type_dist": {
      "type": "splunk.pie",
      "title": "Message Type Distribution",
      "dataSources": { "primary": "ds_message_type_dist" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColorsByField": {
          "Order Message": "#00D2FF",
          "Price Update": "#53A051",
          "Dead Letter": "#DC4E41"
        }
      }
    },
    "viz_top_queues": {
      "type": "splunk.bar",
      "title": "Top Message Queues",
      "dataSources": { "primary": "ds_top_queues" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Messages",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_dead_letters_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Dead Letter Events",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_recent_dead_letters": {
      "type": "splunk.table",
      "title": "Dead Letter Events",
      "dataSources": { "primary": "ds_recent_dead_letters" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 130 } },
      { "item": "viz_kpi_total_messages", "type": "block", "position": { "x": 0, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_dead_letters", "type": "block", "position": { "x": 300, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_price_updates", "type": "block", "position": { "x": 600, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_message_rate", "type": "block", "position": { "x": 900, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_message_flow", "type": "block", "position": { "x": 0, "y": 250, "w": 750, "h": 350 } },
      { "item": "viz_message_type_dist", "type": "block", "position": { "x": 750, "y": 250, "w": 450, "h": 350 } },
      { "item": "viz_top_queues", "type": "block", "position": { "x": 0, "y": 600, "w": 1200, "h": 300 } },
      { "item": "viz_dead_letters_header", "type": "block", "position": { "x": 0, "y": 900, "w": 1200, "h": 50 } },
      { "item": "viz_recent_dead_letters", "type": "block", "position": { "x": 0, "y": 950, "w": 1200, "h": 400 } }
    ]
  }
}
